    std::vector<int> list_decending = {5, 4, 3, 2, 1};
    std::vector<int> list_none = {1, 3, 2, 5, 4};

    std::cout << "Список (растечки):"
              << (checkOrder(list_ascending) == Ред::растечки ? "Подредено по растечки редослед" : "Не е подредено по растечки редослед")
              << std::endl;
    std::cout << "Список (опаѓачки):"
